export const 鎮宅金銀 = (bi) => {
    const u = bi.u, k = 2.7;
    const X = (c) => (c - 3.95) * k;
    const Z = (r) => (r - 0.7) * k + 2;
    const 線 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 圈 = (x, z, r = 0.28) => {
        const c = bi.ctx;
        c.save();
        c.lineWidth = 0.3 * u;
        bi.A(X(x), Z(z), r * k);
        c.restore();
    };
    const 連 = (a, b) => {
        const dx = b[0] - a[0], dz = b[1] - a[1], L = Math.hypot(dx, dz), t = 0.4 / L;
        線(p => p.M(X(a[0] + dx * t), Z(a[1] + dz * t)).L(X(b[0] - dx * t), Z(b[1] - dz * t)));
    };
    // 符頭：桿＋雙菱連鏈＋左圈柱＋右圈柱雙列
    線(p => p.M(X(1.1), Z(1.0)).L(X(6.5), Z(0.9)));
    圈(0.8, 1.0);
    圈(6.8, 0.9);
    const 菱點 = [[3.4, 2.2], [2.2, 3.6], [4.6, 3.5], [3.4, 4.9],
        [2.2, 6.2], [4.6, 6.1], [3.4, 7.4]];
    for (const p_ of 菱點)
        圈(p_[0], p_[1]);
    連([3.4, 2.2], [2.2, 3.6]);
    連([3.4, 2.2], [4.6, 3.5]);
    連([2.2, 3.6], [3.4, 4.9]);
    連([4.6, 3.5], [3.4, 4.9]);
    連([3.4, 4.9], [2.2, 6.2]);
    連([3.4, 4.9], [4.6, 6.1]);
    連([2.2, 6.2], [3.4, 7.4]);
    連([4.6, 6.1], [3.4, 7.4]);
    for (const z of [2.2, 3.6, 5.0, 6.4])
        圈(0.8, z);
    for (const z of [2.5, 3.9, 5.3, 6.7]) {
        圈(5.8, z);
        圈(6.8, z - 0.1);
    }
    // 匚口箱對
    線(p => p.M(X(0.8), Z(8.5)).L(X(0.8), Z(10.5)).L(X(3.2), Z(10.45))
        .L(X(3.2), Z(8.45)));
    線(p => p.M(X(0.9), Z(9.5)).L(X(3.1), Z(9.45)), 0.34);
    線(p => p.M(X(3.8), Z(8.5)).L(X(3.8), Z(10.45)).L(X(6.2), Z(10.4))
        .L(X(6.2), Z(8.45)).L(X(3.75), Z(8.5)));
    線(p => p.M(X(3.9), Z(9.5)).L(X(6.1), Z(9.45)), 0.34);
    // 桁二
    線(p => p.M(X(0.9), Z(11.1)).L(X(6.7), Z(11.0)), 0.42);
    線(p => p.M(X(0.9), Z(11.9)).L(X(6.7), Z(11.8)), 0.42);
    // 手風琴迴帶＋厂張足
    線(p => p.M(X(1.0), Z(12.6)).L(X(5.9), Z(12.55))
        .C(X(6.4), Z(12.55), X(6.4), Z(13.5), X(5.9), Z(13.55))
        .L(X(1.8), Z(13.6)).C(X(1.3), Z(13.6), X(1.3), Z(14.55), X(1.8), Z(14.6))
        .L(X(5.9), Z(14.55)).C(X(6.4), Z(14.55), X(6.4), Z(15.5), X(5.9), Z(15.55))
        .L(X(1.8), Z(15.6)).C(X(1.3), Z(15.6), X(1.3), Z(16.55), X(1.8), Z(16.6))
        .L(X(6.2), Z(16.55)));
    線(p => p.M(X(1.2), Z(17.1)).C(X(1.0), Z(17.8), X(0.9), Z(18.4), X(0.9), Z(18.9)));
    線(p => p.M(X(6.3), Z(16.9)).C(X(6.6), Z(17.6), X(6.7), Z(18.3), X(6.7), Z(18.8)));
};
